SELECT cover_type, MIN(ba_ha) AS min_ba_ha
FROM forest_data
GROUP BY cover_type;

SELECT AVG(ba_ha) AS average_ba_ha_inactive
FROM forest_data
WHERE status = 'inactive';

SELECT cover_type
FROM forest_data
WHERE data_id = 0 AND status = 'inactive';

SELECT cover_type, average_height, average_lifespan
FROM cover_types
ORDER BY average_lifespan DESC;

SELECT description
FROM cover_types
WHERE cover_type = 'OAK';
